import { createWorkflow, Step } from 'mastra/workflows';
import { z } from 'zod';

const codeGenWorkflow = createWorkflow({
  name: 'code-generation',
  steps: [
    new Step({
      name: 'generate',
      inputSchema: z.object({ prompt: z.string() }),
      llm: 'gpt-4o',
      outputSchema: z.object({
        code: z.string(),
        explanation: z.string()
      }),
    }),
    new Step({
      name: 'execute',
      inputSchema: z.object({ code: z.string() }),
      tools: ['sandbox-exec'],
      outputSchema: z.object({
        stdout: z.string(),
        stderr: z.string(),
        passed: z.boolean()
      }),
    }),
    new Step({
      name: 'refine',
      inputSchema: z.object({ code: z.string(), feedback: z.string() }),
    })
  ]
});

import { createTool } from 'mastra/tools';

const sandboxExecutor = createTool({
  name: 'sandbox-exec',
  description: 'Execute code in secure Node.js sandbox',
  inputSchema: z.object({
    code: z.string().describe('JavaScript/TypeScript code'),
    tests: z.array(z.string()).optional()
  }),
  execute: async ({ code, tests }) => {
    const sandbox = await createNodeSandbox();
    const result = await sandbox.run(code);

    if (tests) {
      const testResults = await sandbox.runTests(tests);
      return {
        stdout: result.stdout,
        stderr: result.stderr,
        passed: testResults.every(t => t.passed)
      };
    }

    return result;
  }
});

import { createAgent } from 'mastra/agents';

const codeAgent = createAgent({
  name: 'code-gen-agent',
  llm: 'gpt-4o',
  memory: {
    type: 'conversation',
    maxTokens: 8000,
    retrieval: async (query) => {
      // Retrieve relevant code iterations
      return await memoryStore.search({
        query,
        filter: { type: 'code-iteration' },
        limit: 5
      });
    }
  },
  tools: [sandboxExecutor]
});

const testStep = new Step({
  name: 'validate-tests',
  inputSchema: z.object({
    code: z.string(),
    requirements: z.string()
  }),
  llm: 'gpt-4o',
  systemPrompt: `Generate comprehensive unit tests for the provided code that verify:\n1. Syntax validity\n2. Core functionality\n3. Edge cases\n4. Error handling`,
  outputSchema: z.object({
    tests: z.array(z.string()),
    testResults: z.object({
      passed: z.number(),
      failed: z.number(),
      coverage: z.number()
    })
  }),
});

