import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
  project: 'mastra-code-gen'
});

const withVexValidation = async (workflow) => {
  return {
    ...workflow,
    steps: workflow.steps.map(step => ({
      ...step,
      execute: async (input) => {
        const result = await step.execute(input);

        // Vex validates code safety & syntax
        const verified = await vex.verify({
          data: result,
          checks: [
            'code_safety',
            'syntax_validity',
            'no_credential_leakage',
            'dependency_safety'
          ],
          context: { language: 'typescript', useCase: 'code-generation' }
        });

        if (!verified.valid) {
          throw new Error(`Vex validation failed: ${verified.issues.join(', ')}`);
        }

        return result;
      }
    }))
  };
};

const secureWorkflow = withVexValidation(codeGenWorkflow);

const secureSandboxExecutor = createTool({
  ...sandboxExecutor,
  execute: async (input) => {
    const rawResult = await sandboxExecutor.execute(input);

    // Vex normalizes malformed tool outputs
    const normalized = await vex.normalize({
      data: rawResult,
      schema: z.object({
        stdout: z.string(),
        stderr: z.string(),
        passed: z.boolean()
      }),
      repair: true
    });

    // Additional safety scan
    await vex.verify({
      data: input.code,
      checks: ['execution_sandboxing'],
      context: { sandbox: true }
    });

    return normalized;
  }
});

const secureMemoryRetrieval = async (query: string) => {
  const rawMemory = await memoryStore.search({ query, limit: 10 });

  // Vex filters unsafe/stale context
  const safeContext = await vex.filter({
    data: rawMemory,
    checks: [
      'code_safety',
      'no_credential_leakage',
      'syntax_validity'
    ],
    context: {
      maxAge: '1h',
      useCase: 'code-generation-memory'
    }
  });

  return safeContext.validItems.slice(0, 5);
};

codeAgent.memory.retrieval = secureMemoryRetrieval;
